section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/finops-devops-cost-alerts.json",
  "title": "FinOps Cost Alerts and Anomaly Workflow",
  "type": "object",
  "required": [
    "thresholds_pct",
    "anomaly_detector",
    "alert_routing",
    "investigation_template_path",
    "exec_report_cadence",
    "owner",
    "last_reviewed"
  ],
  "properties": {
    "thresholds_pct": {
      "type": "array",
      "minItems": 4,
      "items": {
        "type": "integer",
        "minimum": 1,
        "maximum": 100
      }
    },
    "anomaly_detector": {
      "type": "object",
      "required": [
        "enabled",
        "provider"
      ]
    },
    "alert_routing": {
      "type": "array",
      "minItems": 1,
      "items": {
        "type": "object",
        "required": [
          "team",
          "channel"
        ]
      }
    },
    "investigation_template_path": {
      "type": "string"
    },
    "exec_report_cadence": {
      "enum": [
        "weekly",
        "biweekly",
        "monthly"
      ]
    },
    "owner": {
      "type": "string"
    },
    "last_reviewed": {
      "type": "string"
    }
  },
  "additionalProperties": false
}
